import { useSpring } from "@react-spring/web";
import type React from "react";
import { useState } from "react";
import { useResizeDetector } from "react-resize-detector";

import { ComponentLoadingSpinner } from "../../shared/component-loading-spinner";
import { Colour } from "../../theme";
import type {
    BaseProps,
    LinkListItemProps,
    LinkListLazyProps,
} from "../internal-types";
import {
    Expandable,
    ExpandableChild,
    ToggleButton,
    ToggleButtonLabel,
    ViewMoreIcon,
} from "../link-list.styles";
import { LinkListItems } from "./common";

type Props<T> = Omit<BaseProps<T>, "className" | "data-testid"> &
    Omit<LinkListLazyProps, "loadMode">;
export const LazyLinkList = <T,>({
    items,
    style,
    onItemClick,
    loadMore,
    onLoadMore,
    customLabels,
}: Props<T>) => {
    // =============================================================================
    // CONST, STATE, REFS
    // =============================================================================
    const [isLoading, setIsLoading] = useState(false);

    const resizeDetector = useResizeDetector();
    const childRef = resizeDetector.ref;

    // =============================================================================
    // EVENT HANDLERS
    // =============================================================================
    const handleListItemClick = (
        event: React.MouseEvent<HTMLAnchorElement>,
        item: LinkListItemProps<T>
    ) => {
        /**
         * Individual item's onClick will override
         * the onItemClick callback
         */
        if (item.onClick) {
            event.preventDefault();
            item.onClick(event);
        } else if (onItemClick) {
            event.preventDefault();
            onItemClick(item, event);
        }

        // Do nothing and let default event happen
    };

    const handleClickViewMore = async () => {
        if (isLoading) return;

        setIsLoading(true);
        try {
            await onLoadMore();
        } catch {
            // do nothing
        }
        setIsLoading(false);
    };

    // =============================================================================
    // RENDER FUNCTIONS
    // =============================================================================
    const renderToggle = () => {
        const label = isLoading
            ? "Loading..."
            : customLabels?.viewMore || "View more";

        return (
            <ToggleButton
                type="button"
                onClick={handleClickViewMore}
                data-testid="toggle-button"
                aria-disabled={isLoading}
                $loading={isLoading}
            >
                <ToggleButtonLabel
                    forwardedAs="span"
                    weight="semibold"
                    data-testid="toggle-button-label"
                    aria-busy={isLoading}
                >
                    {label}
                </ToggleButtonLabel>

                {isLoading ? (
                    <ComponentLoadingSpinner color={Colour["text-disabled"]} />
                ) : (
                    <ViewMoreIcon aria-hidden />
                )}
            </ToggleButton>
        );
    };

    // React spring animation configuration
    const expandableStyles = useSpring({
        height: resizeDetector.height,
    });

    return (
        <>
            <Expandable style={expandableStyles} data-testid="content">
                <ExpandableChild ref={childRef}>
                    <LinkListItems
                        data-testid="link-list-items"
                        items={items}
                        handleItemClick={handleListItemClick}
                        style={style}
                    />
                </ExpandableChild>
            </Expandable>
            {loadMore && renderToggle()}
        </>
    );
};
